    },
  },
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0e0e10",
      foreground: "#e2e2e6",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#09090b",
      editor: "#0e0e10",
      terminal: "#09090b",
      statusBar: "#060608",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
