import { useCallback, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES_BY_ID,
  DEFAULT_THEME_ID,
  type ThemeDefinition,
  type ThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme";

type ThemeSnapshot = {
  themeId: ThemeId;
  theme: ThemeDefinition;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function isThemeId(value: unknown): value is ThemeId {
  return value === "t3-dark" || value === "t3-light" || value === "t3-midnight";
}

function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isThemeId(raw) ? raw : DEFAULT_THEME_ID;
}

function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = BUILT_IN_THEMES_BY_ID[themeId];
  document.documentElement.classList.toggle("dark", theme.isDark);
  document.documentElement.style.setProperty("color-scheme", theme.isDark ? "dark" : "light");

  // Override core shadcn semantic vars with theme-specific values
  document.documentElement.style.setProperty("--background", theme.colors.background);
  document.documentElement.style.setProperty("--foreground", theme.colors.foreground);
  document.documentElement.style.setProperty("--accent", theme.colors.accent);
  document.documentElement.style.setProperty("--ring", theme.colors.accent);

  // Theme-specific surface vars (new — consumed by future components and the selector swatches)
  document.documentElement.style.setProperty("--t3-sidebar", theme.colors.sidebar);
  document.documentElement.style.setProperty("--t3-editor", theme.colors.editor);
  document.documentElement.style.setProperty("--t3-terminal", theme.colors.terminal);
  document.documentElement.style.setProperty("--t3-status-bar", theme.colors.statusBar);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent FOUC
applyTheme(getStoredThemeId());

function getSnapshot(): ThemeSnapshot {
  const themeId = getStoredThemeId();
  const theme = BUILT_IN_THEMES_BY_ID[themeId];

  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId, theme };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(id, true);
    emitChange();
  }, []);

  return { themeId: snapshot.themeId, theme: snapshot.theme, setTheme } as const;
}

