import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

const SWATCH_SLOTS = ["background", "sidebar", "accent", "foreground"] as const;

export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(theme.id)}
            className={`flex flex-col rounded-xl border p-3 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent hover:text-foreground"
            }`}
          >
            {/* Color swatch strip */}
            <div className="mb-2.5 flex gap-1.5" aria-hidden="true">
              {SWATCH_SLOTS.map((slot) => (
                <span
                  key={slot}
                  className="h-5 w-5 rounded-md border border-black/10"
                  style={{ background: theme.colors[slot] }}
                />
              ))}
            </div>

            <span className="text-xs font-medium text-foreground">{theme.name}</span>

            {selected ? (
              <span className="mt-1.5 inline-block rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

